-- 2026-07-12-training-days.sql
-- ─────────────────────────────────────────────────────────────────────
-- Structured, reviewable sales-training curriculum.
--
-- One row = one training "day" (a slide breakdown): the point, the
-- verbatim script (array of say/dir lines), coaching notes and a drill.
--
-- Workflow (why the status + token columns exist):
--   • A manager submits a new day  → status = 'pending'  (not live yet)
--   • DeWayne & Neal get an SMS+email (event 'training_day_submitted')
--     with a private link ?= review_token, edit it, then click Activate
--   • Activate                     → status = 'active'   (goes live)
--   • Retiring a day               → status = 'archived'
--
-- The 18 verbatim days from the U.S. Shingle sales manual are seeded here
-- as source='manual', status='active' — fully editable in-system.
--
-- RLS: enabled but fully open (using true) — same open-anon pattern as the
-- rest of the app (no auth). Reviewer mutations still go through a server
-- function that re-checks review_token; browser writes use the anon key.
-- ─────────────────────────────────────────────────────────────────────

create table if not exists training_days (
  id                      uuid primary key default gen_random_uuid(),
  position                integer not null default 0,
  title                   text not null,
  subject                 text,                                   -- chip/reference (e.g. "Slide 1", "Objection Handling")
  theme                   text,                                   -- section / week theme
  on_slide                text,                                   -- the "On the slide:" one-liner
  point                   text,
  script                  jsonb not null default '[]'::jsonb,     -- [{ k:'say'|'dir', t:'...' }]
  coach                   text,
  drill                   text,
  compare                 jsonb,                                  -- optional two-option "Service Includes" comparison
  status                  text not null default 'pending',        -- 'pending' | 'active' | 'archived'
  source                  text not null default 'submission',     -- 'manual' | 'submission'
  review_token            text unique,
  submitted_by_name       text,
  submitted_by_recipient_id uuid,
  activated_at            timestamptz,
  activated_by            text,
  created_at              timestamptz not null default now(),
  updated_at              timestamptz not null default now()
);

create index if not exists training_days_status_position_idx on training_days (status, position);
create index if not exists training_days_review_token_idx on training_days (review_token);

alter table training_days enable row level security;
drop policy if exists training_days_sel on training_days;
drop policy if exists training_days_ins on training_days;
drop policy if exists training_days_upd on training_days;
drop policy if exists training_days_del on training_days;
create policy training_days_sel on training_days for select using (true);
create policy training_days_ins on training_days for insert with check (true);
create policy training_days_upd on training_days for update using (true) with check (true);
create policy training_days_del on training_days for delete using (true);

-- ── Seed: the 18 verbatim manual days (active, editable) ──────────────
-- Idempotent: only seeds when the table has no manual rows yet.
do $seed$
begin
  if not exists (select 1 from training_days where source = 'manual') then
    insert into training_days (position, title, subject, theme, on_slide, point, script, coach, drill, compare, review_token, status, source, activated_at) values
    (1, $md$Why U.S. Shingle? — The Company$md$, $md$Slide 1$md$, $md$Who We Are & Why It Matters$md$, $md$The credibility list — 15 years, veteran-owned, 5-star, licensed & insured, finance-vetted, not the cheapest.$md$, $md$Establish us as the safe, proven, vetted choice before price ever comes up. It's all tie-down questions — make the homeowner agree out loud.$md$, $md$[{"k":"say","t":"When Dealing with a company for your roof how important is it too you that they are likely to be around in the future if you have a need or if something goes wrong?"},{"k":"dir","t":"(Most will answer with its important)"},{"k":"say","t":"Absolutely, Studies show that over 50% of companies fail to make it to 5 years and 80% of companies fail to make it their 15th birthday. Since its important that the company you choose is around when you need them, I have great news. We are now over 15 years old which should demonstrate that the likelihood of us being around if you need us is extremely high wouldn't you agree?"},{"k":"say","t":"We are also a Veteran owned company how important is that to you?"},{"k":"dir","t":"(If they say important, ask them why. It gets them to start selling themselves on us. Worst case if they said it's not you can follow up with a statement that says. I figure if we can trust them to protect our freedom, we can certainly trust them to protect our home!)"},{"k":"say","t":"What did you do to research us before today? Would you agree that people are more likely to complain about companies when they had a bad experience then say good things about them when they had a great experience? Well, the good news is we have tons of 5 Star reviews, so you will find that everything we talk about today will be back up by our rating on Google."},{"k":"say","t":"As consumers we've gone from checking the BBB to now just seeing what others say on Google. Truthfully, we are pretty limited on ways to check on the viability of a business. Let me ask you this, If you were a bank and you wanted to help homeowners finance a roof, you'd want to make sure you got paid back right? So, you'd definitely would like to make sure you only loan money to people who's roofing companies are solid and do good work otherwise you risk people not wanting to pay, make sense?"},{"k":"say","t":"Well, another feather in our cap is we are also one of just a few companies licensed by the State of Florida to offer direct to consumer financing. In fact, some of these finance companies that have agreed to put their name next to ours took over two months to approve us. They have looked at our finances, our install record, our record with the State and so on. The good news is they did your homework for you in vetting us out."},{"k":"say","t":"Even if you didn't finance, you would agree that doing business with a company that can pass that kind of rigorous background check is better than a chuck in a truck right?"},{"k":"say","t":"When protecting everything you own and everyone you love is the cheapest the most important thing or is getting the best value for your money important?"}]$md$::jsonb, $md$The longest, most important open. Teach reps to ask each question, pause, and let the homeowner answer. Land the veteran and finance-vetting points as proof, not brags.$md$, $md$Reps deliver Slide 1 end-to-end, hitting every tie-down question and pausing for the answer.$md$, null, gen_random_uuid()::text, 'active', 'manual', now()),
    (2, $md$Our Roofing License$md$, $md$Slide 2$md$, $md$Who We Are & Why It Matters$md$, $md$The Florida triple-C (CCC) roofing license.$md$, $md$Prove statewide licensing and make the homeowner aware the liability to verify it falls on them.$md$, $md$[{"k":"say","t":"This is our Roofing license, notice it's a triple C license, that means it's a statewide approved license, a lot of roofing contractors only have an RC license which is specific to JUST one county. Did you know that if you hire unlicensed contractors, not only can the county fine you up to 5k but they can also force you to do the job again? The liability falls on the homeowner to verify licensing. You want a fully licensed contractor, right?"}]$md$::jsonb, $md$The CCC vs. RC distinction is the differentiator — make sure reps can explain it plainly, then land the tie-down.$md$, $md$Reps explain triple-C vs. RC and the 5k / redo-the-job risk, then the closing question.$md$, null, gen_random_uuid()::text, 'active', 'manual', now()),
    (3, $md$Liability Insurance$md$, $md$Slide 3$md$, $md$Who We Are & Why It Matters$md$, $md$Certificate of Liability Insurance — our 1M / 2M policy.$md$, $md$Contrast the bare state minimum with our coverage; frame it as the homeowner's protection.$md$, $md$[{"k":"say","t":"When choosing a roofing company would you rather deal with a company that just does the minimum when it comes to liability insurance, or would you rather deal with a company that wants to make sure that everything is covered from beginning to end?"},{"k":"say","t":"The State of Florida requires a minimum of $100,000 injury and $25,000 property damage. Our policy is 1million 2 million to make sure while we are doing the work if anything happens you can feel comfortable to know you are not exposed at all. You aren't opposed to having more coverage are you?"}]$md$::jsonb, $md$The numbers do the work — 100k/25k minimum vs. our 1M/2M. Say the small numbers slowly, the big ones with confidence.$md$, $md$Reps deliver the minimum-vs-ours contrast and both tie-downs.$md$, null, gen_random_uuid()::text, 'active', 'manual', now()),
    (4, $md$You Already Need a Roof$md$, $md$Slide 4$md$, $md$Who We Are & Why It Matters$md$, $md$Need solar? No. Water softener? No. New windows? No. MUST replace your roof.$md$, $md$Disarm the 'sell' — position the roof as a need, not a pitch. Delivered warm, a little funny.$md$, $md$[{"k":"say","t":"One of the parts I like most about my job is that I don't really have to sell anything. I mean roofing is not like Solar or water softeners where you might have to be convinced you need it. You already know you need a roof, right? I mean nobody wakes up in the morning and goes \"Oh I can't wait to buy a roof today\". So, I'm not really here because you want me to be I'm really only here because you need me to be."}]$md$::jsonb, $md$This lowers the homeowner's guard. The 'nobody wakes up wanting to buy a roof' line should earn a smile.$md$, $md$Reps deliver it conversationally, landing the humor.$md$, null, gen_random_uuid()::text, 'active', 'manual', now()),
    (5, $md$Chuck in the Truck vs. a Real Company$md$, $md$Slide 5$md$, $md$Why Us, Why Now$md$, $md$Skydiving · Experience Matters · Peace of Mind so You Can Sleep Well.$md$, $md$Justify not being the cheapest — experience, volume, and being our own manufacturer.$md$, $md$[{"k":"say","t":"Have you ever been skydiving? Well let's say we get a little crazy and decide we are going skydiving, when we got there they said we had our pick at who is going to pack our parachutes. One of them has 5 years of experience and the other has over 15 years of experience. Who are you going to pick?"},{"k":"dir","t":"(They are going to say 15 years, Then ask them why?)"},{"k":"say","t":"Exactly because experience matters, doesn't it? Let's face it if there is just a 1% chance that the chute doesn't open that is 1% to much am I right? So, since this the roof is protecting most of what you own but more importantly everyone you love, is that any less important?"},{"k":"say","t":"Now let's add one more layer. The guy with 5 years of experience charges $200 but the guy with over 15 years charges 20% more at $240 to pack the chutes. You're still picking the guy with all the experience, aren't you? It's because experience is worth paying just a little more for the peace of mind to know the chute will open or the roof wont leak am, I right?"},{"k":"say","t":"One of the other advantages to using a company that does the volume we do, is that we attract the best crews because we keep them busy year-round and this way we get to make sure we have the best possible people at your home."},{"k":"say","t":"Suppliers also sell their materials to us for less because of the same reason, in fact they fight over us because we do volume and are consistent. This allows us the ability to pass some savings on to you but still be competitive in the market. Obviously, we need to be profitable to be around for you in the future, you understand that right?"},{"k":"say","t":"Lastly, we are not just a roofer, but we are also a manufacture. If you decide today to buy your last roof than you will be not only dealing with the roofing company but also the manufacture as well. So, one stop shopping as we have a facility here in Florida and manufacture all our own metal roof panels and trim to go with it."}]$md$::jsonb, $md$The heart of the pitch — it justifies the price. Reps must make the homeowner say '15 years' and 'why' out loud before moving on.$md$, $md$Reps run the full skydiving analogy, getting both verbal commitments.$md$, null, gen_random_uuid()::text, 'active', 'manual', now()),
    (6, $md$Why Replace Today — The Savings$md$, $md$Slide 6$md$, $md$Why Us, Why Now$md$, $md$Insurance Savings · Energy Savings up to 40% · Material Costs Go Up Every Year.$md$, $md$Three cost-of-waiting reasons. Plants the energy package and the insurance-shopping seed.$md$, $md$[{"k":"say","t":"Saving money is important to just about everyone I talk to you, I imagine you enjoy saving money as well. So, when it comes to saving money when is the best time to start? Well it was actually before you met me but we can't change that. Look the truth is as long as there aren't any serious leaks you could probably wait a day, a week, a month or even 6 months to replace your roof. However, there are also some very strong reasons why you probably shouldn't wait another day."},{"k":"say","t":"I would love to say that you will only save money on your homeowners insurance if you let us do your roof, however that's just not the case. We might be however, the only company that brings it up, but please promise me that no matter who you go with you will most certainly shop your insurance once the roof is on."},{"k":"say","t":"The truth is homeowners are saving on average 30% on what they are paying now. How much is your homeowner's insurance right now?"},{"k":"dir","t":"(Calculate what they said at throw out the number)"},{"k":"say","t":"By taking action today that's money every month you could be saving instead of throwing away to your insurance company."},{"k":"say","t":"Another area that you won't find any of our competitors talking about is helping you save money on your electric bill. We have a complete package to go with the roof that I'll discuss more in a minute, but I would imagine you wouldn't be opposed to the electric company helping to pay for your new roof, would you? Most of our customers save up to 40% or more on their electric bill."},{"k":"say","t":"Again choose to reroof now and keep that savings in your pocket. Wait to reroof and its paying 40% more than you need to, over and over again."},{"k":"say","t":"Another strong reason to move forward today is the material and labor savings. Multiple times a year shingle and metal manufactures raise prices. The roofs we did just a short few years ago are almost half as much as the same roofs today. Choosing today simply means you pay less."},{"k":"say","t":"Another savings only happens due to supply and demand. Currently sales are slow because of the time of year so our suppliers have given us some incentives which we just pass on to you. However, I can't tell you if those end today or tomorrow or next week. So as the saying goes you snooze you lose!"},{"k":"say","t":"Again, it's not a question of IF you'll need to replace, I think we've already established that, it's just a matter of when. Can you see how waiting based on just these three points only can cost you thousands more?"}]$md$::jsonb, $md$Reps should actually calculate 30% of the homeowner's stated insurance out loud. This slide pre-sells the energy package (Day 16).$md$, $md$Reps deliver all three savings reasons and do the live insurance math.$md$, null, gen_random_uuid()::text, 'active', 'manual', now()),
    (7, $md$Low Bid Price Match Guarantee$md$, $md$Slide 7$md$, $md$Why Us, Why Now$md$, $md$Low Bid Price Match Guarantee · Peace of Mind that Saves You Time.$md$, $md$Kill 'I want more quotes' with the match-plus-10%-refund guarantee.$md$, $md$[{"k":"say","t":"We also offer something that we have not seen with any other roofing company. There are so many roofers to choose from today and well we just want to make sure you're comfortable making the choice to go with us, so we have a Low Bid Match Guarantee policy. Simply stated if you find it for less, we will not only match it but refund you 10% of the difference as well. What this gives you is peace of mind to know you paid the best price to get the best value."},{"k":"say","t":"Have you ever bought something on sale only to find when you got home it was cheaper somewhere else? Frustrating right? I have one that I think is worse. You find something on sale and say to yourself, \"Self I am learning from my past mistakes and I'm not buying it today because I'm pretty sure I can find it for less elsewhere, so you don't buy it. So, you go searching for it at a better price only to learn that it isn't cheaper anywhere else. So, you go back to the place it was on sale and now the sale is over!! Exactly both are equally frustrating, and we know this that is why we put together the Guarantee. Go ahead and take advantage of our sale but afterwards shop us and if you can beat it, we will match it plus refund you 10% of the difference. Let me ask you this, we are the only company I know of that does this. Do you think the company would do this if it happened a lot?"}]$md$::jsonb, $md$The final question — 'would we do this if it happened a lot?' — is the mic-drop. Teach reps to ask it and stop talking.$md$, $md$Reps deliver the guarantee and the 'on sale' story, ending on the closing question.$md$, null, gen_random_uuid()::text, 'active', 'manual', now()),
    (8, $md$What Can We Offer?$md$, $md$Slide 8$md$, $md$Why Us, Why Now$md$, $md$Asphalt shingle · metal panel · flat/TPO · tile · decorative metal · commercial.$md$, $md$We install every roof type — the electrician-who-only-does-switches analogy.$md$, $md$[{"k":"say","t":"You had said earlier that it was important for you that the company have experience, that they know what they are doing? Let me ask you a question, if you hired an electrician to come in to work on some outlets for you and when they got there, they said \"I'm sorry we only do switches, would you find that weird? Exactly you're either a licensed electrician or you're not."},{"k":"say","t":"Unfortunately, you're going to find that most roofers only do shingle and nothing else or they do metal and nothing else. So, if someone comes to you that way, I want you to think of the electrician that only does switches. With us if it is a roofing product, we are pros at installing it."}]$md$::jsonb, $md$Callback to 'experience' from the survey. The electrician analogy makes single-product competitors look amateur.$md$, $md$Reps deliver the electrician analogy and tie it to full-service.$md$, null, gen_random_uuid()::text, 'active', 'manual', now()),
    (9, $md$Our Installation Process$md$, $md$Slide 9$md$, $md$Process & Products$md$, $md$The 13-step process — permits, photos, foreman, code re-nail, peel-n-stick, rotted-decking, cleanup, walkthrough.$md$, $md$Remove the fear of mess and chaos — and quietly pre-frame the rotted-wood change order before it's a surprise.$md$, $md$[{"k":"say","t":"Yes, we pull permits. Why? It's what reputable companies do. I can't tell you how many times we get a call because a homeowner paid chuck in a truck for an inexpensive roof. Then to find out their insurance company sends them a notice later asking them to replace the new roof they just paid for. You see Insurance companies; they go by permits. So now they must pay twice. Did they save any money, you tell me?"},{"k":"say","t":"We take pictures, lots and lots of pictures. We document everything. It keeps everything professional. Here is what we've experienced. Homeowners will walk around after the job is done and point out damaged screens and ask us to replace them. To the photos we go, only to discover they were damaged prior to us being there. No we don't think they were trying to get one overt on us."},{"k":"say","t":"Simply put when was the last time you walked all around your home doing a thorough inspection? Or the same thing happens with the drive, they never noticed the big crack before we put the dump trailer there. So naturally we damaged the driveway, until we break out the photos. It keeps everyone responsible which is just the best policy don't you agree."},{"k":"say","t":"We will assign a Jobsite foreman to you and your home. He is there for EVERYTHING install related. You will get his cell phone, and you can't possibly call him to much. If you need anything at all, please call them 24/7 7 days a week. Their single job responsibility is to make sure you have the best possible experience!"},{"k":"say","t":"Unlike other companies we do not use dumpsters. They can seriously damage your driveway. We only use dump trailers which roll in on tires and roll away on tires leaving no chance of damaging your driveway."},{"k":"say","t":"We always strip the old shingles off. Yes, a roof over is permitted once by the building department but it voids the manufacture warranty, and it cuts the life of the shingle in half. We just will not do that kind of work for our customers. Do you want a warranty? Do you want the roof to last its entire designed life?"},{"k":"say","t":"Instead of using felt paper or even synthetic underlayment we put peel and stick on all our roofs. Its self-sealing for one which prevents leaks but it's also much safer here in Florida as we could have a pop-up thunderstorm at any time. Felt can blow off before the main shingles are applied. With peel and stick you couldn't pull it off if you wanted too. So, you get a better-quality roof and some peace of mind during the install."},{"k":"say","t":"Here is the only thing we don't know for sure. Rotted decking and or fascia. Both must be replaced per building code and of course you don't want us putting new material over rotted wood. You are responsible for any rotted wood we find. We will take pictures of all of it so you can always see what was damaged and what we replaced. Normally if you don't have and stains in your ceilings you should not require much if any wood to be replaced, maybe a sheet or two. I'll show you that pricing when we get to that part."},{"k":"say","t":"We do our best to clean up everything, to leave your yard better than we found it. However, a reroof is the messiest project you could ever do at your home. We sweep, we use magnets, we sweep some more and go around your yard with rolling magnets. It's just impossible to get them all, there are over 10,000 nails in your average roof. So please if we reroof your home don't go barefoot in the yard for a couple weeks. Give some time for the missed nail to settle down deep."},{"k":"say","t":"Lastly once the job is finished that Job Site foreman you've become friends with is going to walk around the house with you to get your approval that you are happy with everything. If you see anything at all just let us know and we will address it right then. Once you are totally happy, he will ask you for the balance owed and for a Google review on the spot."}]$md$::jsonb, $md$The longest teaching slide. The permit 'pay twice' story and the rotted-decking pre-frame are the two that matter most — drill those.$md$, $md$Reps walk the full process; spot-check the permit story and the rotted-wood pre-frame.$md$, null, gen_random_uuid()::text, 'active', 'manual', now()),
    (10, $md$Shingle Colors$md$, $md$Slide 10$md$, $md$Process & Products$md$, $md$GAF Timberline HDZ color options (Tamko also available).$md$, $md$Present shingle colors; both GAF and Tamko are top-tier, Tamko slightly higher wind rating.$md$, $md$[{"k":"say","t":"These are the colors available regionally here for shingles if that's what you decide to do. We have GAF on the slide but also install Tamko as well which has a slightly higher wind rating but both have the best warranty and products on the market."}]$md$::jsonb, $md$Short slide. Reps offer Tamko's higher wind rating as an option, not a push.$md$, $md$Reps present the shingle options and the GAF/Tamko distinction.$md$, null, gen_random_uuid()::text, 'active', 'manual', now()),
    (11, $md$Metal Colors & Emissivity$md$, $md$Slide 11$md$, $md$Process & Products$md$, $md$Metal color chart; emissivity demo; ZXL screw; exposed fastener vs. standing seam.$md$, $md$Reframe color choice around heat (4% shingle vs. 84% metal) and explain the two metal systems.$md$, $md$[{"k":"say","t":"These are all the Metal colors that you can choose from. Have you ever heard the word emissivity? It's a fancy word that means"},{"k":"dir","t":"(point to your iPad)"},{"k":"say","t":"if this was out in the sun it would get hot right? When I take it out of the sun how long is it going to stay hot? The lower the number the more it absorbs the heat. To give you an idea. The shingles you have on your home are only rated at 4% emissivity."},{"k":"say","t":"Basically, if I go on your roof tomorrow morning before the sun comes up it will still be warm from the day before. Now out of all the colors on this page which do you think would be the hottest?"},{"k":"dir","t":"(They always pick black)"},{"k":"say","t":"Absolutely! But with the metal and the special paint what is the emissivity?"},{"k":"dir","t":"(point to the E)"},{"k":"say","t":"yeah 84% compared to 4 % now you can get the color you want without the fear it is going to make things hotter. Based on that which color do you think you would really want, knowing you don't have to worry about that?"},{"k":"say","t":"One thing to point out about exposed fastener are the screws. This is our lifetime screw. Older screws used metal washers which due to thermal expansion would cause the screws to come loose or they used rubber washers which would dry rot and have issues. We use a the ZXL lifetime screw with color matching caps, so you can't see the screws from a distance and yet the neoprene washer will not dry rot or suffer from thermal expansion creating a lasting roof that doesn't leak."},{"k":"say","t":"The difference between the Exposed Fastener and the Standing Seam is that the standing seams screws are hidden under the metal but the wind rating isn't as high as the exposed fastener system and the Standing seam is about 25% more expensive. You really just need to decide what's most important to you when choosing between these two. You can't go wrong with either of them."}]$md$::jsonb, $md$The emissivity bit is interactive — reps must point to the iPad and get the 'black is hottest' answer. It ties color right back to energy savings.$md$, $md$Reps run the emissivity demo interactively and explain exposed vs. standing seam.$md$, null, gen_random_uuid()::text, 'active', 'manual', now()),
    (12, $md$Permalock Aluminum Shingle$md$, $md$Slide 12$md$, $md$Process & Products$md$, $md$Permalock — all-aluminum shingle, lifetime labor + material.$md$, $md$The premium 'last roof you'll ever buy' — we're the semi-exclusive statewide dealer.$md$, $md$[{"k":"say","t":"Here we have Permalock, which by the way we are the semi exclusive dealer for this product in Florida. There is only one other company, and they only do the Naples Florida area, whereas we are cover the entire state. They were grandfathered in before we came to town so to speak. This is an all-aluminum shingle with a Lifetime Guarantee on both Labor and Material. No, it's not cheap but it will be the only roof you'll ever have to buy for this home which could save you untold tens of thousands of dollars in the future."}]$md$::jsonb, $md$'Only roof you'll ever buy' is the value frame that justifies the price. Reps shouldn't apologize for the cost.$md$, $md$Reps present Permalock and the lifetime / last-roof value.$md$, null, gen_random_uuid()::text, 'active', 'manual', now()),
    (13, $md$Our Work$md$, $md$Slides 13–14$md$, $md$Proof, Warranty & Energy$md$, $md$A couple of real install photos — the exposed-fastener black roof.$md$, $md$Real proof; the fasteners disappear from the street (callback to the metal slide).$md$, $md$[{"k":"say","t":"These are just a couple pictures of some of our installs, I could show you hundreds if you had time. The black roof here is an exposed fastener and you can see from the street view you cant even really see the fasteners."}]$md$::jsonb, $md$Let the photos talk; point out the hidden-fastener detail that ties back to Day 11.$md$, $md$Reps narrate the install photos and make the fastener callback.$md$, null, gen_random_uuid()::text, 'active', 'manual', now()),
    (14, $md$Jobsite Prep$md$, $md$Slide 15$md$, $md$Proof, Warranty & Energy$md$, $md$Tarp for the dump trailer + plywood protecting the garage doors.$md$, $md$We protect the property before we start — and fix any snafus to make it right.$md$, $md$[{"k":"say","t":"Here is an example of our jobsite prep, we lay down a tarp where the dump trailer will go and also protect the garage doors with some plywood just in case. We take every precaution to make sure the install goes smooth without any issue. Sometimes we do encounter some snafus but we always go the extra mile to correct them and make sure you are 1000% happy."}]$md$::jsonb, $md$Reinforces the 'we protect your home' theme from the install slide.$md$, $md$Reps explain the prep steps and the 1000%-happy commitment.$md$, null, gen_random_uuid()::text, 'active', 'manual', now()),
    (15, $md$Our Warranty$md$, $md$Slide 16$md$, $md$Proof, Warranty & Energy$md$, $md$Free 10-Year No-Leak workmanship warranty · transferable.$md$, $md$Free 10-year no-leak, no hidden fees, transfers with the house.$md$, $md$[{"k":"say","t":"Our Free 10 Year no leak guarantee covers anything short of a catastrophic loss for the next decade, regardless of if it's a material or labor or whatever. There is no trip fee, surcharge or any other hidden costs with our warranty. If there's a problem inside of the next decade we cover the cost and fix the problem. And if you sell the house, the warranty goes with it to the next customer."}]$md$::jsonb, $md$Emphasize 'no trip fee / no hidden costs' and transferable (resale value).$md$, $md$Reps explain the 10-year no-leak and the transfer to a new owner.$md$, null, gen_random_uuid()::text, 'active', 'manual', now()),
    (16, $md$The Energy Saver Package$md$, $md$Slides 17–21$md$, $md$Proof, Warranty & Energy$md$, $md$Radiant heat → 3-part fix: R-38 insulation, duct sealing, NASA radiant barrier (97%).$md$, $md$The upsell that 'pays for the roof' — capture the bill first, then walk the 3-part fix to up to 40% savings.$md$, $md$[{"k":"say","t":"Speaking of radiant heat, what would you say your average electric bill is in the summer? Now how about in the winter? Ok so then overall you'd say your average bill is about____?"},{"k":"say","t":"I'm asking because for most of our customers we do an energy package which helps them cover the cost of the roof. In other words, if I could on a cash flow basis make your new roof nearly free you might add me to the Christmas Card list?"},{"k":"say","t":"Here let me show you what I mean. Here in Florida about 70% of your electric bill is because of air conditioning. So, it would stand to reason if we can keep your AC from working hard or at all then we can cut your bill way down, right?"},{"k":"say","t":"Well with all the pluses to living here we have some challenges too. See up north they get to run ductwork in the basement where it's cool, down here we run all our duct work in the attic where it's crazy hot."},{"k":"say","t":"In the summer attic temperatures can reach 150 degrees or higher. Ever been up there in the summer? You have like 12 seconds and then you can't breathe. It's so hot."},{"k":"say","t":"Well, what that means is that you are PAYING, with your hard-earned money, to cool the air to 50 degrees because you're about to pipe it up into the furnace so that when it finally comes out over here it's 74 degrees. Yes, I know that makes zero sense but that's the downside to how we build here."},{"k":"say","t":"Now there is a solution to fix this problem, and we've helped LOTS of homeowners fix their houses already. I know what you're thinking, \"this is going to be expensive\" or \"money is tight right now I can't afford anything\". Well don't worry because the fix I'm going to show you isn't going to cost you anymore than you are already paying right now! In fact, as I said earlier, I won't ask you for a single penny ever."},{"k":"say","t":"The solution is 3 parts. The first is to add more insulation as most homes don't have anywhere near enough for our Florida heat. We installed R-38 or about this much (use your hands to show about 15\") compared to what most people have which is this much (use your hands to show about 4\") Ill pop my head up there in a minute to double check what you have."},{"k":"say","t":"The second is to seal the ducts you have in the attic. You see neither the builder nor the guy who installed your AC were concerned about your electric bill were they? They were more interested in doing the job quickly to get paid and move on. What that means is that your ducts were never sealed or sealed properly which means the air you are paying to cool isn't making into the house but instead getting lost up there. So, we will seal and reseal them using sealing mastic. The other issue with improperly sealed ducts is air quality in your home. The return ducts are sucking in dust, pollen, mold and anything else floating around up there."},{"k":"say","t":"The third part which is the most CRITICAL is something called Radiant Barrier. It's high-tech stuff that literally reflects 97% of the sun's radiating heat from ever entering your attic. It was invented by NASA for the space shuttle. So now instead of having to pay to cool your air to 50 degrees (scroll back) you only need to cool it to about 70 degrees instead (scroll forward), because we will have dramatically reduced the temperature in your attic."},{"k":"say","t":"This will not only save you up to 40% or more off your Utility bill but it will also extend the life of your AC system. If the AC is running half as much it's going to last longer, isn't it?"},{"k":"say","t":"Obviously if you have it already, you're good to go but I've only seen one home so far that had a radiant barrier installed. let me just check first and then I can give you the break down and the investment for just the roof and then what it looks like for the whole package."}]$md$::jsonb, $md$Biggest upsell in the pitch. Reps must capture the summer/winter bill first, use the hand gestures for R-38, and land the 'cool to 50 to deliver 74' absurdity. The 'nearly free / Christmas card list' line sets up the reveal.$md$, $md$Reps run the whole energy sequence, including the bill capture and the 50°→74° story.$md$, null, gen_random_uuid()::text, 'active', 'manual', now()),
    (17, $md$How Can I Pay?$md$, $md$Slide 22$md$, $md$Payment & The Close$md$, $md$Cash or credit card, plus three financing lanes.$md$, $md$Present payment as lanes and let them choose. Never promise a rate, term, or approval.$md$, $md$[{"k":"say","t":"Obviously, we do like to get paid for what we do so we can always take cash or credit card. If you choose to go with a card and get the points just know that a 3% processing fee is automatically added in as that's exactly what the bank charges us to run your card."},{"k":"say","t":"Most of our customers prefer to hold onto their cash and break the roof out over time. As I said earlier, we have many companies with partner with to do this for you and with a host of options as well. We have no credit-based financing in certain areas through the PACE program, we have traditional credit financing based on your score and income and of course we have some premium financing options as well like same as cash and no payments no interest for up to 24 months. Those programs require excellent credit scores and quite frankly may not be good fit for everyone."}]$md$::jsonb, $md$Present the lanes (PACE / traditional / same-as-cash) and let the homeowner pick. The 3% card fee is passed through, not markup — say so. Don't promise approval or terms.$md$, $md$Reps present all payment lanes accurately, with no over-promising.$md$, null, gen_random_uuid()::text, 'active', 'manual', now()),
    (18, $md$Ask for the Business — The Big Reveal$md$, $md$Slide 23$md$, $md$Payment & The Close$md$, $md$The assessment sheet — roof-only vs. the whole package, then silence.$md$, $md$The close: present the two options and go completely silent. First one to talk loses.$md$, $md$[{"k":"dir","t":"Go to the Assessment Sheet."},{"k":"say","t":"Alright so here is how this breaks down for your home. As you shared, you'd rather do"},{"k":"dir","t":"(shingle/metal etc)"},{"k":"say","t":"So with everything included such as"},{"k":"dir","t":"(list off 6 to 10 items included in the roof product they chose)"},{"k":"say","t":"The monthly investment would be ________. Now when we combine just the roof with our energy saving program you get everything we just discussed PLUS you get the R38 Insulation, the radiant barrier to keep all the heat out eliminating those hot and cold areas as well as dramatically extending the life of you're A/C plus you get the duct sealing or resealing which of course improves the air quality in your home for ____________ who has the allergies. So after I deduct the 40% of you electric bill your net effective payment for all of this is ____________."},{"k":"say","t":"So which would you prefer, just the roof for ________ or would you prefer to have everything for just ____________."},{"k":"dir","t":"(stop speaking. Do NOT speak again for ANY reason until they do)"}]$md$::jsonb, $md$THE most important discipline in the whole pitch: after the two-option question, the rep says nothing. Drill the silence until it's uncomfortable — that's the point.$md$, $md$Full assessment-sheet close role-play — rep presents both options, then stays silent until the 'homeowner' speaks first.$md$, $md${"leftCap":"Just the roof","left":["High Wind Resistance","Premium Secondary Water Barrier","Veteran Owned Company in Business over 15 years","10-Year Workmanship No Leak Warranty","Transferable when you sell"],"rightCap":"Roof + Energy Saver Package","rightPlus":"Everything on the left PLUS","right":["Radiant Barrier 97%","Insulation R38","Attic Duct Sealing or Re-Sealing","Lifetime Products","Extends the Life of your HVAC","Improves indoor Air Quality"]}$md$::jsonb, gen_random_uuid()::text, 'active', 'manual', now());
  end if;
end $seed$;
